 504→            }
 505→        };
 506→    });
 507→
 508→    // We need to find the index in the history to update the DB
 509→    setHistory(prevHistory => {
 510→        const index = prevHistory.findIndex(item => item.timestamp === analysisId);
 511→        if (index !== -1) {
